import{_ as a,o as i,c as l,ae as t}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"게이트웨이 아키텍처","description":"WebSocket 게이트웨이 아키텍처, 컴포넌트, 클라이언트 흐름","frontmatter":{"title":"게이트웨이 아키텍처","description":"WebSocket 게이트웨이 아키텍처, 컴포넌트, 클라이언트 흐름"},"headers":[],"relativePath":"concepts/architecture.md","filePath":"concepts/architecture.md","lastUpdated":null}'),o={name:"concepts/architecture.md"};function s(n,e,c,d,r,h){return i(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="게이트웨이-아키텍처" tabindex="-1">게이트웨이 아키텍처 <a class="header-anchor" href="#게이트웨이-아키텍처" aria-label="Permalink to &quot;게이트웨이 아키텍처&quot;">​</a></h1><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><ul><li>단일 장기 실행 <strong>게이트웨이</strong>가 모든 메시징 서피스를 소유합니다 (Baileys를 통한 WhatsApp, grammY를 통한 Telegram, Slack, Discord, Signal, iMessage, WebChat).</li><li>제어 플레인 클라이언트 (macOS 앱, CLI, 웹 UI, 자동화)는 구성된 바인드 호스트 (기본값 <code>127.0.0.1:18789</code>)의 <strong>WebSocket</strong>을 통해 게이트웨이에 연결합니다.</li><li><strong>노드</strong> (macOS/iOS/Android/헤드리스)도 <strong>WebSocket</strong>을 통해 연결하지만, 명시적 캡스/커맨드와 함께 <code>role: node</code>를 선언합니다.</li><li>호스트당 하나의 게이트웨이; 이는 WhatsApp 세션을 여는 유일한 곳입니다.</li><li><strong>canvas 호스트</strong>는 게이트웨이 HTTP 서버에서 다음 경로로 제공됩니다: <ul><li><code>/__openclaw__/canvas/</code> (에이전트 편집 가능 HTML/CSS/JS)</li><li><code>/__openclaw__/a2ui/</code> (A2UI 호스트) 게이트웨이와 동일한 포트 (기본값 <code>18789</code>)를 사용합니다.</li></ul></li></ul><h2 id="컴포넌트와-흐름" tabindex="-1">컴포넌트와 흐름 <a class="header-anchor" href="#컴포넌트와-흐름" aria-label="Permalink to &quot;컴포넌트와 흐름&quot;">​</a></h2><h3 id="게이트웨이-데몬" tabindex="-1">게이트웨이 (데몬) <a class="header-anchor" href="#게이트웨이-데몬" aria-label="Permalink to &quot;게이트웨이 (데몬)&quot;">​</a></h3><ul><li>프로바이더 연결을 유지합니다.</li><li>타입화된 WS API를 노출합니다 (요청, 응답, 서버 푸시 이벤트).</li><li>인바운드 프레임을 JSON Schema에 대해 검증합니다.</li><li><code>agent</code>, <code>chat</code>, <code>presence</code>, <code>health</code>, <code>heartbeat</code>, <code>cron</code> 같은 이벤트를 방출합니다.</li></ul><h3 id="클라이언트-mac-앱-cli-웹-관리자" tabindex="-1">클라이언트 (mac 앱 / CLI / 웹 관리자) <a class="header-anchor" href="#클라이언트-mac-앱-cli-웹-관리자" aria-label="Permalink to &quot;클라이언트 (mac 앱 / CLI / 웹 관리자)&quot;">​</a></h3><ul><li>클라이언트당 하나의 WS 연결.</li><li>요청 전송 (<code>health</code>, <code>status</code>, <code>send</code>, <code>agent</code>, <code>system-presence</code>).</li><li>이벤트 구독 (<code>tick</code>, <code>agent</code>, <code>presence</code>, <code>shutdown</code>).</li></ul><h3 id="노드-macos-ios-android-헤드리스" tabindex="-1">노드 (macOS / iOS / Android / 헤드리스) <a class="header-anchor" href="#노드-macos-ios-android-헤드리스" aria-label="Permalink to &quot;노드 (macOS / iOS / Android / 헤드리스)&quot;">​</a></h3><ul><li><code>role: node</code>로 <strong>동일한 WS 서버</strong>에 연결합니다.</li><li><code>connect</code>에서 장치 ID를 제공합니다; 페어링은 <strong>장치 기반</strong> (역할 <code>node</code>)이며 승인은 장치 페어링 저장소에 있습니다.</li><li><code>canvas.*</code>, <code>camera.*</code>, <code>screen.record</code>, <code>location.get</code> 같은 커맨드를 노출합니다.</li></ul><p>프로토콜 세부사항:</p><ul><li><a href="/openclaw-docs-ko/gateway/protocol">게이트웨이 프로토콜</a></li></ul><h3 id="webchat" tabindex="-1">WebChat <a class="header-anchor" href="#webchat" aria-label="Permalink to &quot;WebChat&quot;">​</a></h3><ul><li>채팅 히스토리 및 전송에 게이트웨이 WS API를 사용하는 정적 UI.</li><li>원격 설정에서 다른 클라이언트와 동일한 SSH/Tailscale 터널을 통해 연결합니다.</li></ul><h2 id="연결-생명주기-단일-클라이언트" tabindex="-1">연결 생명주기 (단일 클라이언트) <a class="header-anchor" href="#연결-생명주기-단일-클라이언트" aria-label="Permalink to &quot;연결 생명주기 (단일 클라이언트)&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Client</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Gateway</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Client-&gt;&gt;Gateway: req:connect</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: res (ok)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Note right of Gateway: or res error + close</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Note left of Client: payload=hello-ok&lt;br&gt;snapshot: presence + health</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: event:presence</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: event:tick</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Client-&gt;&gt;Gateway: req:agent</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: res:agent&lt;br&gt;ack {runId, status:&quot;accepted&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: event:agent&lt;br&gt;(streaming)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Gateway--&gt;&gt;Client: res:agent&lt;br&gt;final {runId, status, summary}</span></span></code></pre></div><h2 id="와이어-프로토콜-요약" tabindex="-1">와이어 프로토콜 (요약) <a class="header-anchor" href="#와이어-프로토콜-요약" aria-label="Permalink to &quot;와이어 프로토콜 (요약)&quot;">​</a></h2><ul><li>트랜스포트: WebSocket, JSON 페이로드가 있는 텍스트 프레임.</li><li>첫 번째 프레임은 반드시 <code>connect</code>이어야 합니다.</li><li>핸드셰이크 이후: <ul><li>요청: <code>{type:&quot;req&quot;, id, method, params}</code> → <code>{type:&quot;res&quot;, id, ok, payload|error}</code></li><li>이벤트: <code>{type:&quot;event&quot;, event, payload, seq?, stateVersion?}</code></li></ul></li><li><code>hello-ok.features.methods</code> / <code>events</code>는 탐색 메타데이터이며, 모든 호출 가능한 헬퍼 라우트의 생성된 덤프가 아닙니다.</li><li>공유 시크릿 인증은 구성된 게이트웨이 인증 모드에 따라 <code>connect.params.auth.token</code> 또는 <code>connect.params.auth.password</code>를 사용합니다.</li><li>Tailscale Serve (<code>gateway.auth.allowTailscale: true</code>) 또는 루프백이 아닌 <code>gateway.auth.mode: &quot;trusted-proxy&quot;</code> 같은 ID 전달 모드는 <code>connect.params.auth.*</code> 대신 요청 헤더에서 인증을 충족합니다.</li><li>비공개 인그레스 <code>gateway.auth.mode: &quot;none&quot;</code>은 공유 시크릿 인증을 완전히 비활성화합니다; 공개/신뢰할 수 없는 인그레스에서는 이 모드를 끄십시오.</li><li>멱등성 키는 부작용이 있는 메서드 (<code>send</code>, <code>agent</code>)에서 안전한 재시도를 위해 필요합니다; 서버는 단기 중복 제거 캐시를 유지합니다.</li><li>노드는 <code>connect</code>에서 <code>role: &quot;node&quot;</code> 및 캡스/커맨드/퍼미션을 포함해야 합니다.</li></ul><h2 id="페어링-로컬-신뢰" tabindex="-1">페어링 + 로컬 신뢰 <a class="header-anchor" href="#페어링-로컬-신뢰" aria-label="Permalink to &quot;페어링 + 로컬 신뢰&quot;">​</a></h2><ul><li>모든 WS 클라이언트 (오퍼레이터 + 노드)는 <code>connect</code>에서 <strong>장치 ID</strong>를 포함합니다.</li><li>새 장치 ID는 페어링 승인이 필요합니다; 게이트웨이는 후속 연결을 위해 <strong>장치 토큰</strong>을 발행합니다.</li><li>직접 로컬 루프백 연결은 동일 호스트 UX를 원활하게 유지하기 위해 자동 승인될 수 있습니다.</li><li>OpenClaw에는 신뢰할 수 있는 공유 시크릿 헬퍼 흐름을 위한 좁은 백엔드/컨테이너 로컬 자체 연결 경로도 있습니다.</li><li>동일 호스트 tailnet 바인드를 포함한 Tailnet 및 LAN 연결은 여전히 명시적 페어링 승인이 필요합니다.</li><li>모든 연결은 <code>connect.challenge</code> 논스에 서명해야 합니다.</li><li>서명 페이로드 <code>v3</code>는 <code>platform</code> + <code>deviceFamily</code>도 바인딩합니다; 게이트웨이는 재연결 시 페어링된 메타데이터를 고정하고 메타데이터 변경에 대한 재페어링이 필요합니다.</li><li><strong>비로컬</strong> 연결은 여전히 명시적 승인이 필요합니다.</li><li>게이트웨이 인증 (<code>gateway.auth.*</code>)은 로컬이든 원격이든 <strong>모든</strong> 연결에 적용됩니다.</li></ul><p>세부사항: <a href="/openclaw-docs-ko/gateway/protocol">게이트웨이 프로토콜</a>, <a href="/openclaw-docs-ko/channels/pairing">페어링</a>, <a href="/openclaw-docs-ko/gateway/security/">보안</a>.</p><h2 id="프로토콜-타이핑-및-코드-생성" tabindex="-1">프로토콜 타이핑 및 코드 생성 <a class="header-anchor" href="#프로토콜-타이핑-및-코드-생성" aria-label="Permalink to &quot;프로토콜 타이핑 및 코드 생성&quot;">​</a></h2><ul><li>TypeBox 스키마가 프로토콜을 정의합니다.</li><li>JSON Schema는 해당 스키마에서 생성됩니다.</li><li>Swift 모델은 JSON Schema에서 생성됩니다.</li></ul><h2 id="원격-액세스" tabindex="-1">원격 액세스 <a class="header-anchor" href="#원격-액세스" aria-label="Permalink to &quot;원격 액세스&quot;">​</a></h2><ul><li><p>권장: Tailscale 또는 VPN.</p></li><li><p>대안: SSH 터널</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18789:127.0.0.1:18789</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span></code></pre></div></li><li><p>동일한 핸드셰이크 + 인증 토큰이 터널을 통해 적용됩니다.</p></li><li><p>TLS + 선택적 고정이 원격 설정의 WS에서 활성화될 수 있습니다.</p></li></ul><h2 id="운영-스냅샷" tabindex="-1">운영 스냅샷 <a class="header-anchor" href="#운영-스냅샷" aria-label="Permalink to &quot;운영 스냅샷&quot;">​</a></h2><ul><li>시작: <code>openclaw gateway</code> (포그라운드, stdout에 로깅).</li><li>헬스: WS를 통한 <code>health</code> (<code>hello-ok</code>에도 포함됨).</li><li>감독: 자동 재시작을 위한 launchd/systemd.</li></ul><h2 id="불변성" tabindex="-1">불변성 <a class="header-anchor" href="#불변성" aria-label="Permalink to &quot;불변성&quot;">​</a></h2><ul><li>정확히 하나의 게이트웨이가 호스트당 단일 Baileys 세션을 제어합니다.</li><li>핸드셰이크는 필수입니다; JSON이 아니거나 connect가 아닌 첫 번째 프레임은 하드 클로즈입니다.</li><li>이벤트는 재생되지 않습니다; 클라이언트는 갭이 있을 때 새로 고쳐야 합니다.</li></ul><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/concepts/agent-loop">에이전트 루프</a> — 상세 에이전트 실행 사이클</li><li><a href="/openclaw-docs-ko/gateway/protocol">게이트웨이 프로토콜</a> — WebSocket 프로토콜 계약</li><li><a href="/openclaw-docs-ko/concepts/queue">큐</a> — 커맨드 큐 및 동시성</li><li><a href="/openclaw-docs-ko/gateway/security/">보안</a> — 신뢰 모델 및 강화</li></ul>`,31)])])}const g=a(o,[["render",s]]);export{u as __pageData,g as default};
